# Animal classes module - demonstrates cross-module inheritance and interfaces

from types import Species, Status, IExaminable, IVaccinateable, Vitals

# Base Animal class
class Animal:
    name: str
    age: int
    species: Species

    def __init__(self, name: str, age: int, species: Species):
        self.name = name
        self.age = age
        self.species = species

    @virtual
    def get_weight(self) -> float:
        return 0.0

    @virtual
    def is_healthy(self) -> bool:
        return self.age < 15

    @virtual
    def speak(self) -> str:
        return "..."

# Dog class - inherits from Animal, implements IVaccinateable, IExaminable
class Dog(Animal, IExaminable, IVaccinateable):
    breed: str

    def __init__(self, name: str, age: int, breed: str):
        super().__init__(name, age, Species.CANINE)
        self.breed = breed

    @override
    def get_weight(self) -> float:
        return 25.5

    @override
    def is_healthy(self) -> bool:
        return self.age < 12 and self.breed != "Bulldog"

    @override
    def speak(self) -> str:
        return "Woof!"

    @override
    def needs_vaccination(self) -> bool:
        return self.age > 0

    @override
    def get_vaccine_type(self) -> str:
        return "Rabies, DHPP"

    def get_vitals(self) -> Vitals:
        return Vitals(101.5, 80)

# Cat class - inherits from Animal, implements only IExaminable
class Cat(Animal, IExaminable):
    indoor: bool

    def __init__(self, name: str, age: int, indoor: bool):
        super().__init__(name, age, Species.FELINE)
        self.indoor = indoor

    @override
    def get_weight(self) -> float:
        return 10.0

    @override
    def is_healthy(self) -> bool:
        return self.age < 18 and self.indoor

    @override
    def speak(self) -> str:
        return "Meow!"

    def get_vitals(self) -> Vitals:
        return Vitals(102.0, 140)

