# Clinic module - manages examinable animals

from types import Status, IExaminable
from animals import Animal, Dog, Cat

# Clinic class using cross-module types
class PetClinic:
    name: str
    animals: list[IExaminable]
    statuses: dict[IExaminable, Status]

    def __init__(self, name: str):
        self.name = name
        self.animals = []
        self.statuses = {}

    def check_in(self, animal: IExaminable) -> None:
        self.animals.append(animal)
        self.statuses[animal] = Status.WAITING

    def start_exam(self, animal: IExaminable) -> None:
        self.statuses[animal] = Status.IN_EXAM

    def complete_exam(self, animal: IExaminable) -> bool:
        healthy: bool = animal.is_healthy()
        self.statuses[animal] = Status.READY
        return healthy

    def get_average_weight(self) -> float:
        if len(self.animals) == 0:
            return 0.0
        total: float = 0.0
        for animal in self.animals:
            total += animal.get_weight()
        return total / float(len(self.animals))

    def count_healthy(self) -> int:
        count: int = 0
        for animal in self.animals:
            if animal.is_healthy():
                count += 1
        return count
